import type { PublishedLinkSummary } from "@/features/links/types";
import type { PublishedNoteSummary } from "@/features/notes/types";
import type { SavedTag } from "@/features/tags/types";

export type PublicContentKind = "note" | "link";

type PublishedPublicContentBase = {
  id: string;
  kind: PublicContentKind;
  title: string;
  summary: string | null;
  publishedAt: Date;
  updatedAt: Date;
  tags: SavedTag[];
};

export type PublishedPublicNote = PublishedPublicContentBase & {
  kind: "note";
  excerpt: string;
  slug: string;
};

export type PublishedPublicLink = PublishedPublicContentBase & {
  kind: "link";
  url: string;
};

export type PublishedPublicContent = PublishedPublicNote | PublishedPublicLink;

const SAFE_PUBLIC_LINK_PROTOCOLS = new Set(["http:", "https:"]);

export function toPublishedPublicNote(note: PublishedNoteSummary): PublishedPublicNote {
  return {
    id: note.id,
    kind: "note",
    title: note.title,
    summary: note.summary,
    publishedAt: note.publishedAt,
    updatedAt: note.updatedAt,
    tags: note.tags,
    excerpt: note.excerpt,
    slug: note.slug
  };
}

export function toPublishedPublicLink(link: PublishedLinkSummary): PublishedPublicLink {
  return {
    id: link.id,
    kind: "link",
    title: link.title,
    summary: link.summary,
    publishedAt: link.publishedAt,
    updatedAt: link.updatedAt,
    tags: link.tags,
    url: link.url
  };
}

export function isSafePublicLinkUrl(url: string) {
  try {
    const parsedUrl = new URL(url);

    return SAFE_PUBLIC_LINK_PROTOCOLS.has(parsedUrl.protocol);
  } catch {
    return false;
  }
}

export function filterSafePublishedContent(items: PublishedPublicContent[]) {
  return items.filter((item) => item.kind !== "link" || isSafePublicLinkUrl(item.url));
}

export function comparePublishedContent(a: PublishedPublicContent, b: PublishedPublicContent) {
  const publishedAtDiff = b.publishedAt.getTime() - a.publishedAt.getTime();

  if (publishedAtDiff !== 0) {
    return publishedAtDiff;
  }

  const updatedAtDiff = b.updatedAt.getTime() - a.updatedAt.getTime();

  if (updatedAtDiff !== 0) {
    return updatedAtDiff;
  }

  return a.title.localeCompare(b.title);
}

export function sortPublishedContent(items: PublishedPublicContent[]) {
  return [...items].sort(comparePublishedContent);
}

import "server-only";

import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { randomUUID } from "node:crypto";

import { mediaRepo } from "@/features/media/repo";
import { ensureMediaRoot, resolveMediaStoragePath } from "@/features/media/storage";
import { getMediaAssetIdsFromMarkdown, getMediaAssetPath, resolveMediaAssetAccess, type MediaAccessMode } from "@/features/media/types";
import { notesRepo } from "@/features/notes/repo";

export type ReadableMediaAsset = {
  accessMode: MediaAccessMode;
  body: Uint8Array<ArrayBuffer>;
  contentType: string;
  sizeBytes: number;
};

const noteImageContentTypes = new Map<string, string>([
  ["image/gif", ".gif"],
  ["image/jpeg", ".jpg"],
  ["image/png", ".png"],
  ["image/webp", ".webp"]
]);
const maxNoteImageBytes = 8 * 1024 * 1024;

function sanitizeUploadFileName(fileName: string, fallbackExtension: string) {
  const normalizedName = path.basename(fileName).trim();
  const extension = path.extname(normalizedName).toLowerCase();
  const baseName = extension ? normalizedName.slice(0, -extension.length) : normalizedName;
  const sanitizedBaseName = baseName.replace(/[^a-zA-Z0-9._-]+/g, "-").replace(/-+/g, "-").replace(/^[-.]+|[-.]+$/g, "");
  const finalBaseName = sanitizedBaseName || "note-image";

  return `${finalBaseName}${fallbackExtension}`;
}

function createNoteImageAltText(fileName: string) {
  const baseName = fileName.replace(/\.[^.]+$/, "");
  const normalized = baseName.replace(/[_-]+/g, " ").replace(/\s+/g, " ").trim();

  return normalized || "Uploaded image";
}

function getNoteImageExtension(contentType: string) {
  return noteImageContentTypes.get(contentType) ?? null;
}

export async function uploadNoteImage(input: { file: File; noteId: string | null; ownerId: string }) {
  const extension = getNoteImageExtension(input.file.type);

  if (!extension) {
    throw new Error("Upload a PNG, JPG, GIF, or WEBP image.");
  }

  if (input.file.size === 0) {
    throw new Error("Upload a non-empty image.");
  }

  if (input.file.size > maxNoteImageBytes) {
    throw new Error("Upload an image smaller than 8 MB.");
  }

  if (input.noteId) {
    const note = await notesRepo.findByIdForOwner(input.ownerId, input.noteId);

    if (!note) {
      throw new Error("The selected note could not be found.");
    }
  }

  const assetId = randomUUID();
  const fileName = sanitizeUploadFileName(input.file.name, extension);
  const storageScope = input.noteId ?? "drafts";
  const storageKey = `note-images/${storageScope}/${assetId}${extension}`;
  const storagePath = resolveMediaStoragePath(storageKey);
  const body = Buffer.from(await input.file.arrayBuffer());

  await ensureMediaRoot();
  await mkdir(path.dirname(storagePath), { recursive: true });
  await writeFile(storagePath, body);
  await mediaRepo.createNoteImageAsset({
    id: assetId,
    ownerId: input.ownerId,
    noteId: input.noteId,
    storageKey,
    fileName,
    contentType: input.file.type,
    sizeBytes: body.byteLength
  });

  return {
    alt: createNoteImageAltText(fileName),
    assetId,
    fileName,
    url: getMediaAssetPath(assetId)
  };
}

export async function claimNoteImageAssetsForNote(ownerId: string, noteId: string, markdown: string) {
  const assetIds = getMediaAssetIdsFromMarkdown(markdown);

  if (assetIds.length === 0) {
    return;
  }

  await mediaRepo.attachOwnerNoteImagesToNote(ownerId, noteId, assetIds);
}

export async function getReadableMediaAsset(assetId: string, viewerOwnerId: string | null): Promise<ReadableMediaAsset | null> {
  const asset = await mediaRepo.findAccessRecordById(assetId);

  if (!asset) {
    return null;
  }

  const accessMode = resolveMediaAssetAccess(asset, viewerOwnerId);

  if (!accessMode) {
    return null;
  }

  try {
    const body = new Uint8Array(await readFile(resolveMediaStoragePath(asset.storageKey)));

    return {
      accessMode,
      body,
      contentType: asset.contentType,
      sizeBytes: asset.sizeBytes
    };
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === "ENOENT") {
      return null;
    }

    throw error;
  }
}

export const mediaAssetKinds = ["note-image", "link-favicon"] as const;

export type MediaAssetKind = (typeof mediaAssetKinds)[number];

export type MediaAssetAccessRecord = {
  id: string;
  ownerId: string;
  kind: MediaAssetKind;
  storageKey: string;
  contentType: string;
  sizeBytes: number;
  note: {
    isPublished: boolean;
    markdown: string;
  } | null;
  link: {
    isPublished: boolean;
  } | null;
};

export type MediaAccessMode = "owner" | "public";

export function getMediaAssetPath(assetId: string) {
  return `/media/${assetId}`;
}

export function getMediaAssetIdsFromMarkdown(markdown: string) {
  const assetIds = new Set<string>();

  for (const match of markdown.matchAll(/\/media\/([a-zA-Z0-9-]+)/g)) {
    const assetId = match[1]?.trim();

    if (assetId) {
      assetIds.add(assetId);
    }
  }

  return [...assetIds];
}

export function isMediaAssetPubliclyVisible(asset: MediaAssetAccessRecord) {
  if (asset.kind === "note-image") {
    return Boolean(asset.note?.isPublished && asset.note.markdown.includes(getMediaAssetPath(asset.id)));
  }

  if (asset.kind === "link-favicon") {
    return Boolean(asset.link?.isPublished);
  }

  return false;
}

export function resolveMediaAssetAccess(asset: MediaAssetAccessRecord, viewerOwnerId: string | null): MediaAccessMode | null {
  if (viewerOwnerId && viewerOwnerId === asset.ownerId) {
    return "owner";
  }

  if (isMediaAssetPubliclyVisible(asset)) {
    return "public";
  }

  return null;
}

import "dotenv/config";

import { mkdir, rm, writeFile } from "node:fs/promises";
