import {
  Button,
  DetailBlock,
  FormField,
  IntroBlock,
  MetadataRow,
  SectionHeading,
  Surface,
  TagChip,
  TagList
} from "@/components/ui/primitives";
import { EnrichmentPendingRefresh } from "@/features/enrichment/components/pending-refresh";
import { EnrichmentStatusBlock } from "@/features/enrichment/components/status-block";
import { searchOwnerContent } from "@/features/search/service";
import { requireOwnerSession } from "@/lib/auth/owner-session";

type SearchPageProps = {
  searchParams?: Promise<{
    q?: string;
  }>;
};

export default async function SearchPage({ searchParams }: SearchPageProps) {
  const owner = await requireOwnerSession();
  const resolvedSearchParams = (await searchParams) ?? {};
  const results = await searchOwnerContent(owner.id, resolvedSearchParams.q);
  const resultCount = results.notes.length + results.links.length;
  const dateFormatter = new Intl.DateTimeFormat("en", { dateStyle: "medium" });
  const hasPendingResults =
    results.notes.some((note) => note.enrichment.status === "pending") ||
    results.links.some((link) => link.enrichment.status === "pending");

  return (
    <div className="feature-layout">
      <EnrichmentPendingRefresh enabled={hasPendingResults} />
      <Surface className="secondary-route-hero" density="compact" tone="hero">
        <IntroBlock
          compact
          description="This search stays inside the owner area. Public readers do not get a search interface in v1."
          eyebrow="Owner search"
          title="Search the private vault"
        >
          <div aria-label="Search overview" className="ui-support-grid secondary-summary-grid">
            <DetailBlock title="Scope">
              <p>Titles, URLs, and shared tag names.</p>
            </DetailBlock>
            <DetailBlock title="Body search">
              <p>Note bodies and link summaries stay out of scope in v1.</p>
            </DetailBlock>
            <DetailBlock title="Current results">
              <p>{results.query ? `${resultCount} match${resultCount === 1 ? "" : "es"}` : "Run a query to inspect the vault."}</p>
            </DetailBlock>
          </div>
        </IntroBlock>
      </Surface>

      <Surface
        action="/app/search"
        as="form"
        className="search-form secondary-search-form"
        density="compact"
        role="search"
        tone="panel"
      >
        <SectionHeading meta="Owner-only retrieval" title="Query" />
        <div className="secondary-search-controls">
          <FormField className="secondary-search-field" label="Query">
            <input
              autoComplete="off"
              className="text-input"
              defaultValue={results.query}
              name="q"
              placeholder="Search note titles, link titles, URLs, or tags"
              type="search"
            />
          </FormField>
          <div className="button-row secondary-search-actions">
            <Button type="submit">Search</Button>
          </div>
        </div>
      </Surface>

      {results.query ? (
        <div className="retrieval-grid secondary-retrieval-grid">
          <Surface className="secondary-list-panel secondary-note-panel" density="compact" tone="panel">
            <SectionHeading meta={`${results.notes.length} result${results.notes.length === 1 ? "" : "s"}`} title="Matching notes" />
            {results.notes.length === 0 ? (
              <p>No private notes matched this query.</p>
            ) : (
              <div className="note-list">
                {results.notes.map((note) => (
                  <article className="note-list-item dashboard-note-item secondary-note-item" key={note.id}>
                    <div className="dashboard-note-primary">
                      <MetadataRow leading>
                        <span>{note.isPublished ? "Published" : "Draft"}</span>
                        <span>{dateFormatter.format(note.updatedAt)}</span>
                      </MetadataRow>
                      <Link className="note-list-link" href={`/app/notes/${note.id}/edit`}>
                        {note.title}
                      </Link>
                      <p className="dashboard-note-excerpt">{note.excerpt || "Empty draft"}</p>
                    </div>
                    <div className="dashboard-note-secondary secondary-note-secondary">
                      <div className="dashboard-note-ai">
                        <strong>AI summary</strong>
                        {note.summary ? (
                          <p className="note-generated-summary dashboard-note-ai-summary">{note.summary}</p>
                        ) : (
                          <p className="field-note dashboard-note-ai-empty">A generated summary will appear here after a successful enrichment run.</p>
                        )}
                      </div>
                      <EnrichmentStatusBlock detailClassName="dashboard-note-ai-detail" state={note.enrichment} />
                      <TagList aria-label="Note tags" className="dashboard-note-tags secondary-note-tags">
                        {note.tags.length === 0 ? (
                          <TagChip muted>No generated tags</TagChip>
                        ) : (
                          note.tags.map((tag) => (
                            <TagChip key={tag.id}>
                              {tag.name}
                            </TagChip>
                          ))
                        )}
                      </TagList>
                    </div>
                  </article>
                ))}
              </div>
            )}
          </Surface>

          <Surface className="secondary-list-panel secondary-link-panel" density="compact" tone="panel">
            <SectionHeading meta={`${results.links.length} result${results.links.length === 1 ? "" : "s"}`} title="Matching links" />
            {results.links.length === 0 ? (
              <p>No private links matched this query.</p>
            ) : (
              <div className="link-list">
                {results.links.map((link) => (
                  <article className="link-list-item secondary-link-item" key={link.id}>
                    <div className="secondary-link-main">
                      <div className="link-list-heading secondary-link-heading">
                        <MetadataRow leading>
                          <span>Private link</span>
                          <span>{dateFormatter.format(link.updatedAt)}</span>
                        </MetadataRow>
                        <a className="note-list-link" href={link.url} rel="noopener noreferrer" target="_blank">
                          {link.title}
                        </a>
                        <p className="link-url">{link.url}</p>
                      </div>
                      <div className="link-list-footer secondary-link-footer">
                        <MetadataRow>
                          <span>Query</span>
                          <span>{results.query}</span>
                        </MetadataRow>
                      </div>
                    </div>
                    <div className="secondary-link-meta">
                      <EnrichmentStatusBlock detailClassName="secondary-link-status" state={link.enrichment} />
                      <div className="note-generated-copy secondary-generated-copy">
                        <strong>AI summary:</strong>
                        {link.summary ? (
                          <p className="link-summary">{link.summary}</p>
                        ) : (
                          <p className="field-note">A generated summary will appear here after a successful enrichment run.</p>
                        )}
                      </div>
                      <div className="note-generated-copy secondary-generated-copy">
                        <strong>AI tags</strong>
                        <TagList aria-label="Link tags">
                          {link.tags.length === 0 ? (
                            <TagChip muted>No generated tags yet</TagChip>
                          ) : (
                            link.tags.map((tag) => (
                              <TagChip key={tag.id}>
                                {tag.name}
                              </TagChip>
                            ))
                          )}
                        </TagList>
                      </div>
                    </div>
                  </article>
                ))}
              </div>
            )}
          </Surface>
        </div>
      ) : (
        <Surface className="secondary-list-panel" density="compact" tone="panel">
          <SectionHeading meta="v1 boundaries" title="Search scope" />
          <p>Search matches note titles, link titles, link URLs, and shared tag names. Note bodies and link summaries stay out of scope in v1.</p>
        </Surface>
      )}
    </div>
  );
}

import "dotenv/config";

import { PrismaBetterSqlite3 } from "@prisma/adapter-better-sqlite3";
import { PrismaClient } from "@prisma/client";
import { expect, test, type Page } from "@playwright/test";

const desktopViewport = { width: 1440, height: 900 };
const mobileViewport = { width: 390, height: 844 };

const databaseUrl = process.env.DATABASE_URL;

if (!databaseUrl) {
  throw new Error("DATABASE_URL must be set before running UI public note tests.");
}

const prisma = new PrismaClient({
  adapter: new PrismaBetterSqlite3({
    url: databaseUrl
  })
});

const seededNote = {
  title: "Public notes should read like finished pages, not dashboards",
  slug: "public-notes-should-read-like-finished-pages-not-dashboards",
  markdown: `## Reading width is a product decision

The public note page should settle the eye quickly. The reader should feel the note before they feel the container around it.

Supporting metadata can stay available without taking the first beat of attention away from the authored text.

### Quiet signals still matter

- Dates should scan quickly.
- Generated tags should sit lower in the hierarchy.
- The note body should keep a steady reading measure.`,
  summary:
    "A public note feels calmer when the authored markdown carries the page and generated metadata stays visible in a subdued supporting position.",
  publishedAt: new Date("2024-05-21T09:30:00.000Z"),
  tags: ["reading", "hierarchy", "public notes"]
} as const;

async function seedPublishedNote() {
  const username = process.env.OWNER_USERNAME ?? "owner";
  const owner = await prisma.user.findUnique({
    where: {
      username
    }
  });

  if (!owner) {
    throw new Error(`Owner account '${username}' must exist before UI public note tests run.`);
  }

  await prisma.note.deleteMany({
    where: {
      ownerId: owner.id
    }
  });

  await prisma.note.create({
    data: {
      ownerId: owner.id,
      title: seededNote.title,
      slug: seededNote.slug,
      markdown: seededNote.markdown,
      excerpt: "A public note page should stay compact, quiet, and reading-first.",
      summary: seededNote.summary,
      enrichmentStatus: "ready",
      isPublished: true,
      publishedAt: seededNote.publishedAt,
      tags: {
        connectOrCreate: seededNote.tags.map((tag) => ({
          where: {
            name: tag
          },
          create: {
            name: tag
          }
        }))
      }
    }
  });
}

async function expectNoHorizontalOverflow(page: Page) {
  const hasOverflow = await page.evaluate(() => document.documentElement.scrollWidth > document.documentElement.clientWidth);

  expect(hasOverflow).toBe(false);
}

async function expectAccessibleStructure(page: Page) {
  const audit = await page.evaluate(() => {
    const issues: string[] = [];

    const getLabelText = (element: Element) => {
      const ariaLabel = element.getAttribute("aria-label")?.trim();
      if (ariaLabel) {
        return ariaLabel;
      }

      const labelledBy = element.getAttribute("aria-labelledby");
      if (labelledBy) {
        const text = labelledBy
          .split(/\s+/)
          .map((id) => document.getElementById(id)?.textContent?.trim() ?? "")
          .join(" ")
          .trim();

        if (text) {
          return text;
        }
      }

      if (
        element instanceof HTMLInputElement ||
        element instanceof HTMLTextAreaElement ||
        element instanceof HTMLSelectElement
      ) {
        const label = element.labels?.[0]?.textContent?.trim();

        if (label) {
          return label;
        }
      }

      return element.textContent?.trim() ?? "";
    };

    const interactive = document.querySelectorAll("a[href], button, input:not([type='hidden']), textarea, select");

    interactive.forEach((element) => {
      if (!getLabelText(element)) {
        const id = element.id ? `#${element.id}` : "";
        issues.push(`unnamed:${element.tagName.toLowerCase()}${id}`);
      }
    });

    document.querySelectorAll("nav").forEach((element, index) => {
      if (!element.getAttribute("aria-label")) {
        issues.push(`unlabeled-nav:${index + 1}`);
      }
    });

    return {
      h1Count: document.querySelectorAll("h1").length,
      issues,
      lang: document.documentElement.lang,
      mainCount: document.querySelectorAll("main").length
    };
  });

  expect(audit.lang).toBe("en");
  expect(audit.mainCount).toBe(1);
  expect(audit.h1Count).toBeGreaterThan(0);
  expect(audit.issues).toEqual([]);
}

async function expectReadingHierarchy(page: Page, viewport: "desktop" | "mobile") {
  const metrics = await page.evaluate(() => {
    const heading = document.querySelector(".public-note-header h1");
    const body = document.querySelector("[data-testid='public-note-markdown']");
    const bodyMeasure = body?.querySelector("p, ul, ol, blockquote, h2, h3");
    const support = document.querySelector("[data-testid='public-note-support']");
    const meta = document.querySelector(".public-note-meta");

    if (!heading || !body || !bodyMeasure || !support || !meta) {
      throw new Error("Public note hierarchy anchors are missing.");
    }

    const headingRect = heading.getBoundingClientRect();
    const bodyRect = body.getBoundingClientRect();
    const bodyMeasureRect = bodyMeasure.getBoundingClientRect();
    const supportRect = support.getBoundingClientRect();
    const metaRect = meta.getBoundingClientRect();

    return {
      bodyMeasureWidth: Math.round(bodyMeasureRect.width),
      bodyTop: Math.round(bodyRect.top),
      headingTop: Math.round(headingRect.top),
      metaTop: Math.round(metaRect.top),
      supportTop: Math.round(supportRect.top),
      viewportWidth: document.documentElement.clientWidth
    };
  });

  expect(metrics.metaTop).toBeLessThan(metrics.headingTop);
  expect(metrics.headingTop).toBeLessThan(metrics.bodyTop);
  expect(metrics.bodyTop).toBeLessThan(metrics.supportTop);
  expect(metrics.bodyMeasureWidth).toBeLessThanOrEqual(viewport === "desktop" ? 760 : metrics.viewportWidth - 32);
}

async function expectSoftenedPublicType(page: Page, viewport: "desktop" | "mobile") {
  const styles = await page.evaluate(() => {
    const heading = document.querySelector(".public-note-header h1");
    const bodyParagraph = document.querySelector("[data-testid='public-note-markdown'] p");
    const supportStrong = document.querySelector("[data-testid='public-note-support'] strong");

    if (!heading || !bodyParagraph || !supportStrong) {
      return null;
    }

    return {
      bodySize: Number.parseFloat(getComputedStyle(bodyParagraph).fontSize),
      headingSize: Number.parseFloat(getComputedStyle(heading).fontSize),
      supportStrongColor: getComputedStyle(supportStrong).color,
      supportStrongSize: Number.parseFloat(getComputedStyle(supportStrong).fontSize)
    };
  });

  expect(styles).not.toBeNull();

  if (!styles) {
    return;
  }

  expect(styles.headingSize).toBeGreaterThan(styles.bodySize + (viewport === "desktop" ? 12 : 9));
  expect(styles.headingSize).toBeLessThan(viewport === "desktop" ? 35 : 32);
  expect(styles.supportStrongSize).toBeLessThan(styles.bodySize);
  expect(styles.supportStrongColor).toBe("rgb(51, 65, 85)");
}

