import Link from "next/link";

import { MetadataRow, TagChip, TagList } from "@/components/ui/primitives";
import { EnrichmentStatusBlock } from "@/features/enrichment/components/status-block";
import { NoteCardImage } from "@/features/notes/components/note-card-image";
import type { NoteSummary } from "@/features/notes/types";

type OwnerNoteCardProps = {
  href: string;
  note: NoteSummary;
  secondary?: boolean;
  updatedAtLabel: string;
};

export function OwnerNoteCard({ href, note, secondary = false, updatedAtLabel }: OwnerNoteCardProps) {
  const itemClassName = secondary ? "note-list-item dashboard-note-item secondary-note-item" : "note-list-item dashboard-note-item";
  const secondaryClassName = secondary ? "dashboard-note-secondary secondary-note-secondary" : "dashboard-note-secondary";
  const tagClassName = secondary ? "dashboard-note-tags secondary-note-tags" : "dashboard-note-tags";

  return (
    <article className={itemClassName}>
      <div className="dashboard-note-primary">
        {note.cardImage ? (
          <NoteCardImage
            frameClassName="note-card-image-frame dashboard-note-image-frame"
            image={note.cardImage}
            imageClassName="note-card-image dashboard-note-image"
            testId="owner-note-card-image"
            title={note.title}
          />
        ) : null}
        <MetadataRow className="dashboard-note-state" leading>
          <span>{note.isPublished ? "Published" : "Draft"}</span>
          <span>{updatedAtLabel}</span>
        </MetadataRow>
        <Link className="note-list-link dashboard-note-link" href={href}>
          {note.title}
        </Link>
        <p className="dashboard-note-excerpt">{note.excerpt || "Empty draft"}</p>
      </div>
      <div className={secondaryClassName}>
        <div className="dashboard-note-ai">
          <strong>AI summary</strong>
          {note.summary ? (
            <p className="note-generated-summary dashboard-note-ai-summary">{note.summary}</p>
          ) : (
            <p className="field-note dashboard-note-ai-empty">A generated summary will appear here after a successful enrichment run.</p>
          )}
        </div>
        <EnrichmentStatusBlock detailClassName="dashboard-note-ai-detail" state={note.enrichment} />
        <TagList aria-label="Note tags" className={tagClassName}>
          {note.tags.length === 0 ? (
            <TagChip muted>No generated tags</TagChip>
          ) : (
            note.tags.map((tag) => (
              <TagChip key={tag.id}>
                {tag.name}
              </TagChip>
            ))
          )}
        </TagList>
      </div>
    </article>
  );
}

import test from "node:test";
import assert from "node:assert/strict";

import { filterSafePublishedContent, sortPublishedContent, toPublishedPublicLink, toPublishedPublicNote } from "../../src/features/public-content/types";

test("toPublishedPublicNote and toPublishedPublicLink preserve the shared public boundary fields", () => {
  const publishedAt = new Date("2026-03-20T10:00:00.000Z");
  const updatedAt = new Date("2026-03-20T11:00:00.000Z");

  const note = toPublishedPublicNote({
    id: "note-1",
    title: "Published note",
    slug: "published-note",
    excerpt: "Note excerpt",
    summary: "Note summary",
    publishedAt,
    updatedAt,
    tags: [{ id: "tag-1", name: "notes" }]
  });

  const link = toPublishedPublicLink({
    id: "link-1",
    title: "Published link",
    url: "https://example.com/published-link",
    summary: "Link summary",
    publishedAt,
    updatedAt,
    tags: [{ id: "tag-2", name: "links" }]
  });

  assert.deepEqual(
    {
      kind: note.kind,
      title: note.title,
      summary: note.summary,
      publishedAt: note.publishedAt,
      updatedAt: note.updatedAt,
      tags: note.tags,
      slug: note.slug,
      excerpt: note.excerpt
    },
    {
      kind: "note",
      title: "Published note",
      summary: "Note summary",
      publishedAt,
      updatedAt,
      tags: [{ id: "tag-1", name: "notes" }],
      slug: "published-note",
      excerpt: "Note excerpt"
    }
  );

  assert.deepEqual(
    {
      kind: link.kind,
      title: link.title,
      summary: link.summary,
      publishedAt: link.publishedAt,
      updatedAt: link.updatedAt,
      tags: link.tags,
      url: link.url
    },
    {
      kind: "link",
      title: "Published link",
      summary: "Link summary",
      publishedAt,
      updatedAt,
      tags: [{ id: "tag-2", name: "links" }],
      url: "https://example.com/published-link"
    }
  );
});

test("sortPublishedContent orders mixed published items by published time, then updated time, then title", () => {
  const sorted = sortPublishedContent([
    {
      id: "link-b",
      kind: "link",
      title: "Zulu reference",
      summary: null,
      publishedAt: new Date("2026-03-20T09:00:00.000Z"),
      updatedAt: new Date("2026-03-20T09:05:00.000Z"),
      tags: [],
      url: "https://example.com/zulu"
    },
    {
      id: "note-a",
      kind: "note",
      title: "Alpha note",
      summary: null,
      publishedAt: new Date("2026-03-20T09:00:00.000Z"),
      updatedAt: new Date("2026-03-20T09:05:00.000Z"),
      tags: [],
      slug: "alpha-note",
      excerpt: "Alpha excerpt"
    },
    {
      id: "note-newest",
      kind: "note",
      title: "Newest note",
      summary: null,
      publishedAt: new Date("2026-03-21T09:00:00.000Z"),
      updatedAt: new Date("2026-03-21T09:00:00.000Z"),
      tags: [],
      slug: "newest-note",
      excerpt: "Newest excerpt"
    },
    {
      id: "link-mid",
      kind: "link",
      title: "Middle link",
      summary: null,
      publishedAt: new Date("2026-03-20T09:00:00.000Z"),
      updatedAt: new Date("2026-03-20T10:05:00.000Z"),
      tags: [],
      url: "https://example.com/middle"
    }
  ]);

  assert.deepEqual(
    sorted.map((item) => item.id),
    ["note-newest", "link-mid", "note-a", "link-b"]
  );
});

test("filterSafePublishedContent drops unsafe or malformed published links while keeping notes and safe links", () => {
  const filtered = filterSafePublishedContent([
    {
      id: "note-safe",
      kind: "note",
      title: "Safe note",
      summary: null,
      publishedAt: new Date("2026-03-21T09:00:00.000Z"),
      updatedAt: new Date("2026-03-21T09:00:00.000Z"),
      tags: [],
      slug: "safe-note",
      excerpt: "Safe excerpt"
    },
    {
      id: "link-safe",
      kind: "link",
      title: "Safe link",
      summary: null,
      publishedAt: new Date("2026-03-21T08:00:00.000Z"),
      updatedAt: new Date("2026-03-21T08:00:00.000Z"),
      tags: [],
      url: "https://example.com/safe-link"
    },
    {
      id: "link-unsafe",
      kind: "link",
      title: "Unsafe link",
      summary: null,
      publishedAt: new Date("2026-03-21T07:00:00.000Z"),
      updatedAt: new Date("2026-03-21T07:00:00.000Z"),
      tags: [],
      url: "javascript:alert('xss')"
    },
    {
      id: "link-malformed",
      kind: "link",
      title: "Malformed link",
      summary: null,
      publishedAt: new Date("2026-03-21T06:00:00.000Z"),
      updatedAt: new Date("2026-03-21T06:00:00.000Z"),
      tags: [],
      url: "not a url"
    }
  ]);

  assert.deepEqual(
    filtered.map((item) => item.id),
    ["note-safe", "link-safe"]
  );
});
